// Берём конфиг, который пришёл из Config (там уже есть game/template/chat_id/target_count/base_output_dir)
const cfg = $json;

// Базовый объект проекта
const projectConfig = {
  chat_id: cfg.chat_id,
  game: cfg.game || 'Minecraft',
  template: cfg.template || 'Crafty',
  target_count: cfg.target_count || null,
  base_output_dir: cfg.base_output_dir || '/data/content',

  // Описание форматов
  formats: {
    file_with_preview: {
      needs_file: true,
      needs_image: true,
      image: {
        width: 640,
        height: 480,
        orientation: 'landscape',
        format: 'png'
      }
    },
    image_only: {
      needs_file: false,
      needs_image: true,
      image: {
        width: 640,
        height: 480,
        orientation: 'landscape',
        format: 'png'
      }
    },
    skin: {
      needs_file: true,
      needs_image: true,
      file_extensions: ['png'],
      image: {
        width: 360,
        height: 640,
        orientation: 'portrait',
        format: 'png'
      }
    }
  },

  // Секции из ТЗ Crafty Craft
  sections: [
    {
      key: 'mods',
      name: 'Mods',
      format: 'file_with_preview',
      file_extensions: ['mcaddon', 'mcpack'],
      min_categories: 5,
      min_items_per_category: 50
    },
    {
      key: 'items',
      name: 'Items',
      format: 'image_only',
      min_items_total: 50
    },
    {
      key: 'shaders',
      name: 'Shaders',
      format: 'image_only',
      min_items_total: 50
    },
    {
      key: 'skins',
      name: 'Skins',
      format: 'skin',
      min_categories: 5,
      min_items_per_category: 50
    },
    {
      key: 'maps',
      name: 'Maps',
      format: 'file_with_preview',
      file_extensions: ['mcworld'],
      min_categories: 5,
      min_items_per_category: 50
    },
    {
      key: 'addons',
      name: 'Addons',
      format: 'file_with_preview',
      file_extensions: ['mcaddon'],
      min_categories: 5,
      min_items_per_category: 50
    },
    {
      key: 'create_addons',
      name: 'Create Addons',
      format: 'file_with_preview',
      file_extensions: ['mcaddon'],
      min_items_total: 100
    }
  ],

  // Общие текстовые правила
  text_rules: {
    language: 'en',
    title_min: 4,
    title_max: 30,
    description_min: 50,
    description_max: 3000,
    ban_brands: true
  }
};

return [{ json: projectConfig }];

const project = $json;

const tasks = [];

const sections = project.sections || [];

for (const section of sections) {
  const format = section.format;

  // Если у секции есть категории и элементы на категорию
  if (section.min_categories && section.min_items_per_category) {
    for (let categoryIndex = 1; categoryIndex <= section.min_categories; categoryIndex++) {
      tasks.push({
        project_game: project.game,
        project_template: project.template,
        section_key: section.key,
        section_name: section.name,
        format,
        category_index: categoryIndex,
        target_items: section.min_items_per_category,
        base_output_dir: project.base_output_dir,
        text_rules: project.text_rules || {}
      });
    }
  }

  // Если просто общее количество без категорий
  if (section.min_items_total) {
    tasks.push({
      project_game: project.game,
      project_template: project.template,
      section_key: section.key,
      section_name: section.name,
      format,
      category_index: null,
      target_items: section.min_items_total,
      base_output_dir: project.base_output_dir,
      text_rules: project.text_rules || {}
    });
  }
}

// Возвращаем каждый task как отдельный item
return tasks.map(t => ({ json: t }));

// На входе здесь один task из Build Tasks From Sections
// Пример:
// {
//   "project_game": "Minecraft",
//   "project_template": "Crafty",
//   "section_key": "mods",
//   "section_name": "Mods",
//   "format": "file_with_preview",
//   "category_index": 1,
//   "target_items": 50,
//   "base_output_dir": "/data/content",
//   "text_rules": { ... }
// }

const task = $json;

return [{
  json: {
    task,
    // сюда потом добавим sources, items и т.д.
    items: []
  }
}];

const ctx = $json;
const task = ctx.task;

// В реальной жизни тут будет логика:
// - взять список сайтов из конфига,
// - собрать URL-ы страниц по разделу/категории
// Пока просто подставим фейковые урлы по section_key

let sources = [];

switch (task.section_key) {
  case 'mods':
    sources = [
      'https://example.com/mcpe/mods/page1',
      'https://example.com/mcpe/mods/page2'
    ];
    break;
  case 'maps':
    sources = [
      'https://example.com/mcpe/maps/page1'
    ];
    break;
  default:
    sources = [
      'https://example.com/placeholder'
    ];
}

ctx.sources = sources;

return [{ json: ctx }];

const ctx = $json;
const task = ctx.task;
const sources = ctx.sources || [];

const items = [];

sources.forEach((url, index) => {
  items.push({
    json: {
      task,
      source_url: url,
      source_index: index + 1
    }
  });
});

return items;

// ========== AGGREGATE ITEMS ==========
// Собираем все обработанные items в один массив

const items = $input.all();

return [{
  json: {
    items: items.map(i => i.json),
    total_count: items.length
  }
}];

// ========== PREPARE CSV FILE ==========
// Конвертируем CSV в бинарный файл для отправки

const data = $json;
const csvContent = data.csv_content;
const filename = data.filename || 'content.csv';

// Создаём бинарные данные из CSV строки
const binaryData = Buffer.from(csvContent, 'utf-8');

return [{
  json: {
    total_items: data.total_items,
    timestamp: data.timestamp,
    filename: filename
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/csv',
      fileName: filename
    }
  }
}];

