const cfg = $json;

const projectConfig = {
  chat_id: cfg.chat_id,
  game: cfg.game || 'Minecraft',
  template: cfg.template || 'Crafty',
  target_count: cfg.target_count || null,
  base_output_dir: cfg.base_output_dir || '/data/content',

  formats: {
    file_with_preview: {
      needs_file: true,
      needs_image: true,
      image: { width: 640, height: 480, orientation: 'landscape', format: 'png' }
    },
    image_only: {
      needs_file: false,
      needs_image: true,
      image: { width: 640, height: 480, orientation: 'landscape', format: 'png' }
    },
    skin: {
      needs_file: true,
      needs_image: true,
      file_extensions: ['png'],
      image: { width: 360, height: 640, orientation: 'portrait', format: 'png' }
    }
  },

  sections: [
    { key: 'mods', name: 'Mods', format: 'file_with_preview', file_extensions: ['mcaddon', 'mcpack'], min_categories: 5, min_items_per_category: 50 },
    { key: 'items', name: 'Items', format: 'image_only', min_items_total: 50 },
    { key: 'shaders', name: 'Shaders', format: 'image_only', min_items_total: 50 },
    { key: 'skins', name: 'Skins', format: 'skin', min_categories: 5, min_items_per_category: 50 },
    { key: 'maps', name: 'Maps', format: 'file_with_preview', file_extensions: ['mcworld'], min_categories: 5, min_items_per_category: 50 },
    { key: 'addons', name: 'Addons', format: 'file_with_preview', file_extensions: ['mcaddon'], min_categories: 5, min_items_per_category: 50 },
    { key: 'create_addons', name: 'Create Addons', format: 'file_with_preview', file_extensions: ['mcaddon'], min_items_total: 100 }
  ],

  text_rules: {
    language: 'en',
    title_min: 4,
    title_max: 30,
    description_min: 50,
    description_max: 3000,
    ban_brands: true
  }
};

return [{ json: projectConfig }];

const project = $json;
const tasks = [];
const sections = project.sections || [];

for (const section of sections) {
  const format = section.format;

  if (section.min_categories && section.min_items_per_category) {
    for (let categoryIndex = 1; categoryIndex <= section.min_categories; categoryIndex++) {
      tasks.push({
        project_game: project.game,
        project_template: project.template,
        section_key: section.key,
        section_name: section.name,
        format,
        category_index: categoryIndex,
        target_items: section.min_items_per_category,
        base_output_dir: project.base_output_dir,
        text_rules: project.text_rules || {}
      });
    }
  }

  if (section.min_items_total) {
    tasks.push({
      project_game: project.game,
      project_template: project.template,
      section_key: section.key,
      section_name: section.name,
      format,
      category_index: null,
      target_items: section.min_items_total,
      base_output_dir: project.base_output_dir,
      text_rules: project.text_rules || {}
    });
  }
}

return tasks.map(t => ({ json: t }));

const task = $json;

return [{
  json: {
    task,
    items: []
  }
}];

// ========== FETCH SOURCES FOR SECTION ==========
// Реальная логика получения URL источников с mcpedl.com

const ctx = $json;
const task = ctx.task;

// Маппинг разделов на URL категорий mcpedl.com
const categoryMap = {
  'mods': 'https://mcpedl.com/category/mods/',
  'addons': 'https://mcpedl.com/category/mods/addons/',
  'maps': 'https://mcpedl.com/category/maps/',
  'skins': 'https://mcpedl.com/skins/',
  'skin-packs': 'https://mcpedl.com/category/skin-packs/',
  'texture-packs': 'https://mcpedl.com/category/texture-packs/',
  'shaders': 'https://mcpedl.com/resolution/shaders/',
  'seeds': 'https://mcpedl.com/category/seeds/',
  'items': 'https://mcpedl.com/category/mods/',
  'create_addons': 'https://mcpedl.com/category/mods/addons/'
};

// Получаем базовый URL для раздела
const sectionKey = (task.section_key || 'mods').toLowerCase();
const baseUrl = categoryMap[sectionKey] || categoryMap['mods'];

// Генерируем URL для нескольких страниц (пагинация)
// Берём столько страниц, сколько нужно для target_items (примерно 20 items на страницу)
const itemsPerPage = 20;
const targetItems = task.target_items || 50;
const pagesToFetch = Math.min(Math.ceil(targetItems / itemsPerPage), 5);

let sources = [];

for (let i = 1; i <= pagesToFetch; i++) {
  if (i === 1) {
    sources.push(baseUrl);
  } else {
    sources.push(`${baseUrl}page/${i}/`);
  }
}

ctx.sources = sources;
ctx.base_url = 'https://mcpedl.com';

return [{ json: ctx }];

// ========== EXPLODE SOURCES ==========
// Разбиваем массив источников на отдельные items для параллельной обработки

const ctx = $json;
const task = ctx.task;
const sources = ctx.sources || [];

const items = [];

sources.forEach((url, index) => {
  items.push({
    json: {
      task,
      source_url: url,
      source_index: index + 1,
      base_url: ctx.base_url || 'https://mcpedl.com'
    }
  });
});

return items;

// ========== EXTRACT IMAGE LINKS ==========
// Парсим HTML страницы и извлекаем ссылки на моды и картинки

const html = $json.data || $json.body || '';
const task = $input.first().json.task || {};
const sourceIndex = $input.first().json.source_index || 1;
const baseUrl = 'https://mcpedl.com';

const items = [];

// Ищем картинки с forgecdn (CDN mcpedl) и r2.mcpedl.com
const imagePattern = /src="(https:\/\/(?:media\.forgecdn\.net|r2\.mcpedl\.com)\/[^"]+)"/gi;
// Ищем ссылки на страницы модов
const urlPattern = /href="(\/[a-z0-9][a-z0-9-]*\/)"[^>]*>/gi;

const images = [];
const urls = [];
let match;

while ((match = imagePattern.exec(html)) !== null) {
  // Фильтруем аватарки пользователей и иконки
  if (!match[1].includes('/users/') && !match[1].includes('icon')) {
    images.push(match[1]);
  }
}

while ((match = urlPattern.exec(html)) !== null) {
  const url = match[1];
  // Фильтруем служебные страницы
  if (!url.includes('/category/') && 
      !url.includes('/page/') && 
      !url.includes('/user/') &&
      !url.includes('/tag/') &&
      !url.includes('/login') &&
      !url.includes('/dashboard') &&
      !url.includes('/resolution/') &&
      !url.includes('/vip') &&
      !url.includes('/contact') &&
      !url.includes('/skins/') &&
      url.length > 3 &&
      url.length < 100) {
    urls.push(url);
  }
}

// Убираем дубликаты
const uniqueUrls = [...new Set(urls)];
const uniqueImages = [...new Set(images)];

// Комбинируем (берём минимум из двух массивов)
const maxItems = task.target_items || 20;
const minLen = Math.min(uniqueImages.length, uniqueUrls.length, maxItems);

for (let i = 0; i < minLen; i++) {
  // Формируем красивое название из URL
  const rawTitle = uniqueUrls[i]
    .replace(/^\//, '')
    .replace(/\/$/, '')
    .replace(/-/g, ' ')
    .split(' ')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');

  items.push({
    mod_url: baseUrl + uniqueUrls[i],
    image_url: uniqueImages[i],
    raw_title: rawTitle,
    section: task.section_key || 'mods',
    category: task.category_index ? `category_${task.category_index}` : 'general',
    source_index: sourceIndex,
    item_index: i + 1
  });
}

if (items.length === 0) {
  return [{ json: { empty: true, message: 'No items found on page', source_url: $json.source_url } }];
}

return items.map(item => ({ json: item }));

// ========== BUILD CONTENT ITEM ==========
// Формируем объект контента с метаданными

const item = $json;
const timestamp = Date.now();
const runIndex = $runIndex || 0;

// Генерируем уникальное имя файла
const randomSuffix = Math.random().toString(36).substring(2, 8);
const fileName = `${item.section}_${item.source_index}_${item.item_index}_${randomSuffix}.jpg`;

// Генерируем уникальный ID
const id = `${item.section}_${timestamp}_${runIndex}`;

const contentItem = {
  id: id,
  section: item.section,
  category: item.category || 'general',
  image: fileName,
  image_url: item.image_url,
  file: null,
  raw_title: item.raw_title,
  raw_description: '',
  title: '',
  description: '',
  source_url: item.mod_url,
  created_at: new Date().toISOString()
};

return [{ 
  json: contentItem,
  binary: $binary
}];

