// ========== PARSE AI RESPONSE ==========
// Парсим ответ от OpenAI и валидируем данные

const inputItem = $input.first().json;
const aiResponse = $json.choices?.[0]?.message?.content || '{}';

let parsed;
try {
  // Убираем markdown если есть
  const cleanJson = aiResponse
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  parsed = JSON.parse(cleanJson);
} catch (e) {
  // Fallback значения если не удалось распарсить
  parsed = {
    title: (inputItem.raw_title || 'Minecraft Mod').substring(0, 30),
    description: `This ${inputItem.section} adds amazing new content to your Minecraft world. Download and enjoy new gameplay features and experiences!`
  };
}

// Валидация и нормализация title
let title = parsed.title || inputItem.raw_title || 'Minecraft Mod';
// Убираем спецсимволы
title = title.replace(/[^a-zA-Z0-9\s-]/g, '').trim();
// Проверяем длину: 4-30 символов
if (title.length < 4) title = title + ' Mod';
if (title.length > 30) title = title.substring(0, 27) + '...';

// Валидация и нормализация description
let description = parsed.description || '';
// Проверяем длину: 50-3000 символов
if (description.length < 50) {
  description = `${description} This ${inputItem.section} enhances your Minecraft experience with exciting new features and content. Try it now!`;
}
if (description.length > 3000) {
  description = description.substring(0, 2997) + '...';
}

return [{
  json: {
    id: inputItem.id,
    section: inputItem.section,
    category: inputItem.category,
    image: inputItem.image,
    image_url: inputItem.image_url,
    file: inputItem.file || null,
    title: title,
    description: description,
    source_url: inputItem.source_url,
    created_at: inputItem.created_at
  }
}];

// ========== BUILD CSV ==========
// Собираем все items в CSV формат

const data = $json;
const items = data.items || [];

// Формируем строки CSV
const csvRows = items.map((item, index) => {
  return {
    id: item.id || `item_${index + 1}`,
    section: item.section || '',
    category: item.category || '',
    image: item.image || '',
    file: item.file || '',
    title: (item.title || '').replace(/"/g, '""').replace(/\n/g, ' '),
    description: (item.description || '').replace(/"/g, '""').replace(/\n/g, ' ')
  };
});

// Заголовки
const headers = ['id', 'section', 'category', 'image', 'file', 'title', 'description'];

// Формируем CSV строку
let csv = headers.join(',') + '\n';

csvRows.forEach(row => {
  const values = headers.map(h => {
    const val = String(row[h] || '');
    // Оборачиваем в кавычки если есть запятые, переносы или кавычки
    if (val.includes(',') || val.includes('\n') || val.includes('"')) {
      return `"${val}"`;
    }
    return val;
  });
  csv += values.join(',') + '\n';
});

const timestamp = Date.now();

return [{
  json: {
    csv_content: csv,
    total_items: csvRows.length,
    timestamp: timestamp,
    filename: `content_${timestamp}.csv`
  }
}];
